import re
from typing import Pattern
class EmailValidator:
    EMAIL_REGEX: Pattern[str] = re.compile(r"^(?P<local>[a-zA-Z0-9._%+-]+)@(?P<domain>[a-zA-Z0-9.-]+\.[a-zA-Z]{2,})$")

    @staticmethod
    def validate(email: str) -> bool:
        if not isinstance(email, str):
            return False
        match = EmailValidator.EMAIL_REGEX.match(email)
        return match is not None

import re
from typing import Optional, Pattern
class PhoneNumberFormatter:
    PHONE_REGEX: Pattern[str] = re.compile(r"\D*")

    @staticmethod
    def format(phone: str) -> Optional[str]:
        if not isinstance(phone, str):
            return None
        digits = PhoneNumberFormatter.PHONE_REGEX.sub('', phone)[-10:]
        if len(digits) != 10:
            return None
        return f"({digits[:3]}) {digits[3:6]}-{digits[6:]}"

import logging
from typing import Optional
from .email_validator import EmailValidator
from .phone_number_formatter import PhoneNumberFormatter

logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)
class ValidationService:
    @staticmethod
    def validate_email(email: str) -> bool:
        try:
            return EmailValidator.validate(email)
        except Exception as e:
            logger.error(f"Error validating email: {e}")
            return False

    @staticmethod
    def format_phone(phone: str) -> Optional[str]:
        try:
            return PhoneNumberFormatter.format(phone)
        except Exception as e:
            logger.error(f"Error formatting phone: {e}")
            return None

