from unittest import TestCase
from ..email_validator import EmailValidator
class TestEmailValidator(TestCase):
    def test_valid_email(self):
        self.assertTrue(EmailValidator.validate('test@example.com'))

    def test_invalid_email(self):
        self.assertFalse(EmailValidator.validate('invalid-email'))

    def test_non_string_input(self):
        self.assertFalse(EmailValidator.validate(12345))

    def test_empty_string(self):
        self.assertFalse(EmailValidator.validate(''))

    def test_long_email(self):
        self.assertTrue(EmailValidator.validate('a' * 64 + '@example.com'))

    def test_email_with_special_characters(self):
        self.assertTrue(EmailValidator.validate('test.+_%-+@example.com'))

from unittest import TestCase
from ..validation_service import ValidationService
class TestValidationService(TestCase):
    def test_validate_email_valid(self):
        self.assertTrue(ValidationService.validate_email('test@example.com'))

    def test_validate_email_invalid(self):
        self.assertFalse(ValidationService.validate_email('invalid-email'))

    def test_validate_email_non_string(self):
        self.assertFalse(ValidationService.validate_email(12345))

    def test_format_phone_valid(self):
        self.assertEqual(ValidationService.format_phone('(123) 456-7890'), '(123) 456-7890')
        self.assertEqual(ValidationService.format_phone('123-456-7890'), '(123) 456-7890')
        self.assertEqual(ValidationService.format_phone('1234567890'), '(123) 456-7890')
        self.assertEqual(ValidationService.format_phone('+1 (123) 456-7890'), '(123) 456-7890')

    def test_format_phone_invalid(self):
        self.assertIsNone(ValidationService.format_phone('123-45-6789'))
        self.assertIsNone(ValidationService.format_phone('123456789'))
        self.assertIsNone(ValidationService.format_phone('12345678901'))
        self.assertIsNone(ValidationService.format_phone(''))
        self.assertIsNone(ValidationService.format_phone(None))

    def test_format_phone_non_string(self):
        self.assertIsNone(ValidationService.format_phone(1234567890))
